""" This module contains functions that can be used to
find vertical voxels, the points that constitute the ground
in a point cloud
"""

from collections import defaultdict
from itertools import dropwhile
from typing import List, Dict, Tuple, Iterable, Set

import numpy as np
from scipy.spatial import cKDTree

from geosat.cloud import pyvoxels, PointCloud
from geosat.cloud.pyvoxels import VoxelDict3D, VoxelCoords3D


def assemble_vxl_coords(
    point_2d: Tuple[int, int], z_list: Iterable[int]
) -> Iterable[VoxelCoords3D]:
    x, y = point_2d
    return ((x, y, z) for z in z_list)


def find_continuous_part(
    list_in: List[int], max_distance: int = 1
) -> List[Tuple[int, int]]:
    """Find series of int that increments in a list

    :Examples:

    >>> find_continuous_part([1, 2, 3, 5, 6, 9, 11])
    [(1, 3), (5, 6)]

    >>> find_continuous_part([1, 3, 5, 7, 10, 11, 12], max_distance=2)
    [(1, 7), (10, 12)]

    >>> find_continuous_part([5, 3, 10, 5])
    []
    """
    tuples = []
    start_index, count = 0, 0
    for i in range(1, len(list_in)):
        # check above zero to avoid problem if list is not sorted
        if not 0 < (list_in[i] - list_in[i - 1]) <= max_distance:
            if count >= 1:
                tuples.append((list_in[start_index], list_in[i - 1]))
                count = 0
            start_index = i
        else:
            count += 1
    if count != 0:
        tuples.append((list_in[start_index], list_in[start_index + count]))
    return tuples


def find_gaps(list_in: List[int], min_gap_size: int) -> List[Tuple[int, int]]:
    """Find gaps in a list

    :Examples:

    >>> find_gaps([1, 2, 3, 4], min_gap_size=1)
    [(1, 2), (2, 3), (3, 4)]

    >>> find_gaps([1, 2, 3, 10, 12], min_gap_size=4)
    [(3, 10)]

    >>> find_gaps([1, 3, 5, 7], min_gap_size=3)
    []
    """
    tuples = []
    for i in range(len(list_in) - 1):
        if list_in[i + 1] - list_in[i] >= min_gap_size:
            tuples.append((list_in[i], list_in[i + 1]))

    return tuples


def detect_vertical_objects(
    matrix: Dict[Tuple[int, int], List[int]],
    k: float,
    min_meter: float = 5.0,
    max_meter: float = 99.9,
    plane: Tuple[str, str] = ("x", "y"),
) -> List[VoxelCoords3D]:
    """Find vertical objects (poles, tree trunks)

    Vertical objects are found by looking for a continuous stack of
    voxels at the different x,y coordinates.
    To be detected as a vertical object the stack's length must be greater or equal to
    min_meter and the must be lesser than max_meter.

    :param matrix: dict, (x, y): list of z
    :param k: size of voxel
    :param min_meter: minimum length the continuous stack of z coordinates must have
        to be considered as vertical object
    :param max_meter: maximum length of the stack of z coordinates
    :param plane:  useless for now
    :return: list of voxels coordinates which are considered vertical
    """
    vertical_voxels: List[VoxelCoords3D] = []

    for point_2d, z_list in matrix.items():
        continuous_parts = find_continuous_part(z_list, max_distance=2)

        for continuous_part in continuous_parts:
            part_length = continuous_part[1] - continuous_part[0] + 1
            if min_meter <= part_length * k <= max_meter:
                if plane == ("x", "y"):
                    vertical_voxels.extend(
                        assemble_vxl_coords(
                            point_2d,
                            dropwhile(lambda z: z < continuous_part[0], z_list),
                        )
                    )

    return vertical_voxels


def detect_hanging_objects(
    voxels_xy: Dict[Tuple[int, int], List[int]],
    k: float,
    min_dist_to_ground: float = 2.0,
    min_gap_size: float = 1.0,
    use_kdtree: bool = True,
) -> List[VoxelCoords3D]:
    """Find hanging objects (cables, some tree leaves)

    Hanging objects are found by finding the gap in the z coordinate of
    voxels at each (x, y) position.

    Only the first gap is investigated:
    The first gap length and distance to ground are above their respective minimum
    then all voxels at (x,y) that are above the gap are considered "hanged"

    If there are no gap we try to find a approximation of the z corresponding to
    the ground by looking at the neighbourhood to compute the gap length.

    This is done because sometimes the ground is not well caught by the lidar

    """

    if use_kdtree:
        mean_lowest_neighbourhood: Dict[Tuple[int, int], float] = {}

        coords = list(voxels_xy.keys())
        nb_query = min(20, len(coords))
        if coords:
            tree = cKDTree(coords)
            neighbours = tree.query(coords, nb_query)[1]
            if nb_query == 1:
                neighbours = [neighbours]
        else:
            neighbours = []

        for vxl_neighbours, point_2d in zip(neighbours, voxels_xy):
            neighbours_coords = (coords[neighbour] for neighbour in vxl_neighbours)
            z_mins = [voxels_xy[neighbour_xy][0] for neighbour_xy in neighbours_coords]
            mean_lowest_neighbourhood[point_2d] = float(np.mean(z_mins))
    else:
        mean_lowest_z = float(np.mean([voxels_xy[xy][0] for xy in voxels_xy]))
        mean_lowest_neighbourhood = defaultdict(lambda: mean_lowest_z)

    hanging_voxels: List[VoxelCoords3D] = []

    for point_2d, z_list in voxels_xy.items():
        gaps = find_gaps(z_list, int(min_gap_size / k) - 2)

        if gaps:
            gap_length = (gaps[0][1] - gaps[0][0]) * k
            dist_to_ground = (gaps[0][1] - z_list[0]) * k

            if gap_length >= min_gap_size and dist_to_ground >= min_dist_to_ground:
                hanging_voxels.extend(
                    assemble_vxl_coords(
                        point_2d, dropwhile(lambda z: z < gaps[0][1], z_list)
                    )
                )
        else:
            gap_length = (z_list[0] - mean_lowest_neighbourhood[point_2d]) * k
            dist_to_ground = gap_length

            if gap_length >= min_gap_size and dist_to_ground >= min_dist_to_ground:
                hanging_voxels.extend(
                    assemble_vxl_coords(point_2d, voxels_xy[point_2d])
                )

    return hanging_voxels


def approximate_ground(
    k: float,
    voxels: VoxelDict3D,
    vertical_min_meter: float = 0.6,
    hanging_min_gap_size: float = 0.75,
    hanging_min_dist_to_ground: float = 0.75,
) -> List[int]:
    """Easy way to find the ground

    The idea is to find every vertical & hanging objects using a low height threshold
    Then classify as ground everything that is not taken as being vertical or hanging
    """

    voxels_xy = pyvoxels.project_voxels_to_2d(voxels)

    vertical_voxels = detect_vertical_objects(
        voxels_xy, k, min_meter=vertical_min_meter, max_meter=99.9
    )
    hanging_voxels = detect_hanging_objects(
        voxels_xy,
        k,
        min_gap_size=hanging_min_gap_size,
        min_dist_to_ground=hanging_min_dist_to_ground,
    )

    hanging_set = set(hanging_voxels)
    vertical_set = set(vertical_voxels)
    ground: Set[VoxelCoords3D] = {
        voxel
        for voxel in voxels
        if voxel not in vertical_set and voxel not in hanging_set
    }

    adj: Dict[VoxelCoords3D, Set[VoxelCoords3D]] = pyvoxels.adjacency_dict_of_voxels(
        ground
    )
    labels_voxels = pyvoxels.labelize_voxels(adj)
    list_of_points_per_label = pyvoxels.get_points_of_voxels_labels(
        labels_voxels, voxels
    )
    ground_indices = max(list_of_points_per_label, key=len)

    return ground_indices


def approximate_ground_sncf(
    k: float,
    voxels: VoxelDict3D,
    cloud: PointCloud,
    vertical_min_meter: float = 0.6,
    hanging_min_gap_size: float = 0.75,
    hanging_min_dist_to_ground: float = 0.75,
) -> List[int]:
    """This function does the same thing as :func:`approximate_ground`
    (finding the ground) but tries to be more specific to accommodate
    better in a context where the capturing lidar was on a train
    """
    voxels_xy = pyvoxels.project_voxels_to_2d(voxels)

    vertical_voxels = detect_vertical_objects(
        voxels_xy, k, min_meter=vertical_min_meter, max_meter=99.0
    )
    hanging_voxels = detect_hanging_objects(
        voxels_xy,
        k,
        min_gap_size=hanging_min_gap_size,
        min_dist_to_ground=hanging_min_dist_to_ground,
    )

    hanging_set = set(hanging_voxels)
    vertical_set = set(vertical_voxels)
    ground = {
        voxel
        for voxel in voxels
        if voxel not in vertical_set and voxel not in hanging_set
    }

    adj = pyvoxels.adjacency_dict_of_voxels(ground)
    labels_voxels = pyvoxels.labelize_voxels(adj)
    list_of_points_per_label = pyvoxels.get_points_of_voxels_labels(
        labels_voxels, voxels
    )
    biggest_component: List[int] = max(list_of_points_per_label, key=len, default=[])
    ground_point_indices = biggest_component
    # ground_point_indices = [i for points in list_of_points_per_label for i in points]

    ground_voxels = {(x, y, z_list[0]) for ((x, y), z_list) in voxels_xy.items()}
    ground_voxels = {
        voxel
        for voxel in ground_voxels
        if voxel not in hanging_set and voxel not in vertical_set
    }

    zmin_distribution = [
        np.min(cloud.coords[voxels[(x, y, z)], 2]) for (x, y, z) in ground_voxels
    ]
    zmin_q3 = np.nanpercentile(np.array(zmin_distribution), 75)

    for voxel in ground_voxels:
        if np.min(cloud.coords[voxels[voxel], 2]) < zmin_q3:
            for point in voxels[voxel]:
                ground_point_indices.append(point)

    return ground_point_indices
